import android.widget.Button
import android.widget.EditText
import android.widget.Toast
import com.android.billingclient.api.*
import java.security.SecureRandom

class MainActivity : AppCompatActivity(), BillingClientStateListener, PurchasesUpdatedListener {

    private lateinit var billingClient: BillingClient
    private lateinit var purchaseFlowParams: BillingFlowParams
    private lateinit var productIdEditText: EditText
    private lateinit var amountEditText: EditText
    private lateinit var payButton: Button

    override fun onCreate(savedInstanceState: Bundle?) {
        super.onCreate(savedInstanceState)
        setContentView(R.layout.activity_main)

        productIdEditText = findViewById(R.id.productIdEditText)
        amountEditText = findViewById(R.id.amountEditText)
        payButton = findViewById(R.id.payButton)

        billingClient = BillingClient.newBuilder(this).setListener(this).enablePendingPurchases().build()
        billingClient.startConnection(this)

        payButton.setOnClickListener {
            val productId = productIdEditText.text.toString()
            val amount = amountEditText.text.toString()

            if (productId.isNotEmpty() && amount.isNotEmpty()) {
                purchaseFlowParams = BillingFlowParams.newBuilder()
                    .setSkuDetails(getSkuDetails(productId))
                    .build()
                launchBillingFlow(purchaseFlowParams)
            } else {
                Toast.makeText(this, "Please enter product ID and amount", Toast.LENGTH_SHORT).show()
            }
        }
    }

    private fun getSkuDetails(skuId: String): SkuDetails? {
        val querySkuList = listOf(SkuDetailsParams.Product.newBuilder().setProductId(skuId).setType(BillingClient.SkuType.INAPP).build())
        val skuDetailsParams = SkuDetailsParams.newBuilder().setSkusList(querySkuList).setType(BillingClient.SkuType.INAPP).build()
        return billingClient.querySkuDetailsAsync(skuDetailsParams) { billingResult, skuDetailsList ->
            if (billingResult.responseCode == BillingClient.BillingResponseCode.OK && !skuDetailsList.isNullOrEmpty()) {
                return@querySkuDetailsAsync skuDetailsList[0]
            }
            null
        }
    }

    private fun launchBillingFlow(purchaseFlowParams: BillingFlowParams) {
        billingClient.launchBillingFlow(this, purchaseFlowParams)
    }

    override fun onBillingSetupFinished(billingResult: BillingResult) {
        if (billingResult.responseCode == BillingClient.BillingResponseCode.OK) {
            // The BillingClient is ready. You can query purchases here.
        }
    }

    override fun onBillingServiceDisconnected() {
        // Try to restart the connection on the next request to
        // Google Play by calling the startConnection() method.
    }

    override fun onPurchasesUpdated(billingResult: BillingResult, purchases: List<Purchase>?) {
        if (billingResult.responseCode == BillingClient.BillingResponseCode.OK && !purchases.isNullOrEmpty()) {
            for (purchase in purchases) {
                handlePurchase(purchase)
            }
        } else if (billingResult.responseCode == BillingClient.BillingResponseCode.USER_CANCELED) {
            // Handle an error caused by a user cancelling the purchase flow.
        } else {
            // Handle any other error codes.
        }
    }

    private fun handlePurchase(purchase: Purchase) {
        if (purchase.isAcknowledged) {
            // Purchase is already acknowledged
        } else {
            acknowledgePurchase(purchase)
        }
    }

    private fun acknowledgePurchase(purchase: Purchase) {
        val params = AcknowledgePurchaseParams.newBuilder()
            .setPurchaseToken(purchase.purchaseToken)
            .build()

        billingClient.acknowledgePurchase(params) { billingResult ->
            if (billingResult.responseCode == BillingClient.BillingResponseCode.OK) {
                // Purchase is acknowledged
            }
        }
    }

    override fun onDestroy() {
        super.onDestroy()
        billingClient.endConnection()
    }
